51	interface ButtonProps extends useRender.ComponentProps<"button"> {
52	  variant?: VariantProps<typeof buttonVariants>["variant"];
53	  size?: VariantProps<typeof buttonVariants>["size"];
54	}
55	
56	function Button({ className, variant, size, render, ...props }: ButtonProps) {
57	  const typeValue: React.ButtonHTMLAttributes<HTMLButtonElement>["type"] = render
58	    ? undefined
59	    : "button";
60	
61	  const defaultProps = {
62	    className: cn(buttonVariants({ className, size, variant })),
63	    "data-slot": "button",
64	    type: typeValue,
65	  };
66	
67	  return useRender({
68	    defaultTagName: "button",
69	    props: mergeProps<"button">(defaultProps, props),
70	    render,
71	  });
72	}
