114	function hasUnseenCompletion(thread: Thread): boolean {
115	  if (!thread.latestTurn?.completedAt) return false;
116	  const completedAt = Date.parse(thread.latestTurn.completedAt);
117	  if (Number.isNaN(completedAt)) return false;
118	  if (!thread.lastVisitedAt) return true;
119	
120	  const lastVisitedAt = Date.parse(thread.lastVisitedAt);
121	  if (Number.isNaN(lastVisitedAt)) return true;
122	  return completedAt > lastVisitedAt;
123	}
