228	function getServerHttpOrigin(): string {
229	  const bridgeUrl = window.desktopBridge?.getWsUrl();
230	  const envUrl = import.meta.env.VITE_WS_URL as string | undefined;
231	  const wsUrl =
232	    bridgeUrl && bridgeUrl.length > 0
233	      ? bridgeUrl
234	      : envUrl && envUrl.length > 0
235	        ? envUrl
236	        : `${window.location.protocol === "https:" ? "wss" : "ws"}://${window.location.hostname}:${window.location.port}`;
237	  // Parse to extract just the origin, dropping path/query (e.g. ?token=…)
238	  const httpUrl = wsUrl.replace(/^wss:/, "https:").replace(/^ws:/, "http:");
239	  try {
240	    return new URL(httpUrl).origin;
241	  } catch {
242	    return httpUrl;
243	  }
244	}
