import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  type AppTheme,
  type StoredTheme,
  BUILT_IN_THEMES,
  DEFAULT_DARK_THEME_ID,
  DEFAULT_LIGHT_THEME_ID,
  getThemeById,
} from "@t3tools/shared/theme";

export type { StoredTheme };

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

interface ThemeSnapshot {
  stored: StoredTheme;
  systemDark: boolean;
}

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

/**
 * Migrate old "light"/"dark" stored values to named theme IDs, and validate
 * that stored values match known ThemeIds or "system".
 */
function migrateStoredRaw(raw: string | null): StoredTheme {
  if (raw === "system") return "system";
  if (raw === "light") return DEFAULT_LIGHT_THEME_ID;
  if (raw === "dark") return DEFAULT_DARK_THEME_ID;
  if (BUILT_IN_THEMES.some((t) => t.id === raw)) return raw as StoredTheme;
  return "system";
}

function getStored(): StoredTheme {
  return migrateStoredRaw(localStorage.getItem(STORAGE_KEY));
}

function resolveAppTheme(stored: StoredTheme, systemDark: boolean): AppTheme {
  if (stored === "system") {
    return getThemeById(systemDark ? DEFAULT_DARK_THEME_ID : DEFAULT_LIGHT_THEME_ID);
  }
  return getThemeById(stored);
}

function applyTheme(stored: StoredTheme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const theme = resolveAppTheme(stored, getSystemDark());
  document.documentElement.classList.toggle("dark", theme.isDark);

  const style = document.documentElement.style;
  style.setProperty("--background", theme.colors.background);
  style.setProperty("--foreground", theme.colors.foreground);
  style.setProperty("--primary", theme.colors.primary);
  style.setProperty("--ring", theme.colors.primary);
  style.setProperty("--theme-sidebar", theme.colors.sidebar);
  style.setProperty("--theme-editor", theme.colors.editor);
  style.setProperty("--theme-terminal", theme.colors.terminal);
  style.setProperty("--theme-status-bar", theme.colors.statusBar);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

function getSnapshot(): ThemeSnapshot {
  const stored = getStored();
  const systemDark = stored === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.stored === stored &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { stored, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { stored, systemDark } = snapshot;

  const resolvedAppTheme = resolveAppTheme(stored, systemDark);
  const resolvedTheme: "light" | "dark" = resolvedAppTheme.isDark ? "dark" : "light";

  const setTheme = useCallback((next: StoredTheme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(stored);
  }, [stored]);

  return { theme: stored, setTheme, resolvedTheme, resolvedAppTheme } as const;
}

