import { type ReactNode } from "react";
import { useTheme } from "~/hooks/useTheme";

interface ThemeProviderProps {
  readonly children: ReactNode;
}

/**
 * ThemeProvider mounts at the app root and subscribes to the module-level
 * theme store via React, ensuring the DOM stays synchronized with the active
 * theme whenever the component tree mounts or the stored theme changes.
 *
 * Individual components that need theme state should call `useTheme()` directly.
 */
export function ThemeProvider({ children }: ThemeProviderProps) {
  // Subscribe to the module-level store so the root component re-renders (and
  // the useEffect inside useTheme fires) whenever the stored theme changes.
  useTheme();
  return <>{children}</>;
}

