import { BUILT_IN_THEMES, type StoredTheme } from "@t3tools/shared/theme";
import { useTheme } from "~/hooks/useTheme";

const SYSTEM_OPTION = {
  value: "system" as const,
  label: "System",
  description: "Match your OS appearance setting.",
};

/**
 * ThemeSelector renders a radio-button group for picking between System and
 * the three built-in named themes. Named themes show three inline color
 * swatches (background / sidebar / accent) so users can preview each palette
 * before selecting it.
 */
export function ThemeSelector() {
  const { theme, setTheme, resolvedAppTheme } = useTheme();

  const handleSelect = (value: StoredTheme) => {
    setTheme(value);
  };

  return (
    <div className="space-y-2">
      <div role="radiogroup" aria-label="Theme preference" className="space-y-2">
        {/* System option */}
        <ThemeOptionButton
          value={SYSTEM_OPTION.value}
          label={SYSTEM_OPTION.label}
          description={SYSTEM_OPTION.description}
          selected={theme === SYSTEM_OPTION.value}
          onSelect={handleSelect}
        />

        {/* Named themes */}
        {BUILT_IN_THEMES.map((appTheme) => (
          <ThemeOptionButton
            key={appTheme.id}
            value={appTheme.id}
            label={appTheme.label}
            selected={theme === appTheme.id}
            onSelect={handleSelect}
            swatches={[
              { color: appTheme.colors.background, label: "Background" },
              { color: appTheme.colors.sidebar, label: "Sidebar" },
              { color: appTheme.colors.primary, label: "Accent" },
            ]}
          />
        ))}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">{resolvedAppTheme.label}</span>
      </p>
    </div>
  );
}

interface Swatch {
  color: string;
  label: string;
}

interface ThemeOptionButtonProps {
  value: StoredTheme;
  label: string;
  description?: string;
  selected: boolean;
  onSelect: (value: StoredTheme) => void;
  swatches?: Swatch[];
}

function ThemeOptionButton({
  value,
  label,
  description,
  selected,
  onSelect,
  swatches,
}: ThemeOptionButtonProps) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={`flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent"
      }`}
      onClick={() => onSelect(value)}
    >
      <span className="flex flex-col gap-1">
        <span className="text-sm font-medium">{label}</span>
        {description ? (
          <span className="text-xs">{description}</span>
        ) : swatches ? (
          <span className="flex items-center gap-1" aria-hidden="true">
            {swatches.map((swatch) => (
              <span
                key={swatch.label}
                title={swatch.label}
                className="inline-block size-3.5 rounded-full border border-black/10 dark:border-white/10"
                style={{ background: swatch.color }}
              />
            ))}
          </span>
        ) : null}
      </span>

      {selected ? (
        <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Selected
        </span>
      ) : null}
    </button>
  );
}

