export type ThemeId = "t3-light" | "t3-dark" | "t3-midnight";

export type StoredTheme = ThemeId | "system";

export interface ThemeColors {
  background: string;
  foreground: string;
  primary: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface AppTheme {
  id: ThemeId;
  label: string;
  isDark: boolean;
  colors: ThemeColors;
}

export const BUILT_IN_THEMES: ReadonlyArray<AppTheme> = [
  {
    id: "t3-light",
    label: "T3 Light",
    isDark: false,
    colors: {
      background: "oklch(1 0 0)",
      foreground: "oklch(0.271 0.006 286)",
      primary: "oklch(0.488 0.217 264)",
      sidebar: "oklch(0.967 0.001 286)",
      editor: "oklch(1 0 0)",
      terminal: "oklch(0.985 0.001 286)",
      statusBar: "oklch(0.93 0.034 264)",
    },
  },
  {
    id: "t3-dark",
    label: "T3 Dark",
    isDark: true,
    colors: {
      background: "oklch(0.145 0.004 286)",
      foreground: "oklch(0.95 0.001 286)",
      primary: "oklch(0.588 0.217 264)",
      sidebar: "oklch(0.125 0.004 286)",
      editor: "oklch(0.17 0.004 286)",
      terminal: "oklch(0.11 0.004 286)",
      statusBar: "oklch(0.21 0.06 264)",
    },
  },
  {
    id: "t3-midnight",
    label: "T3 Midnight",
    isDark: true,
    colors: {
      background: "oklch(0.11 0.015 264)",
      foreground: "oklch(0.94 0.002 286)",
      primary: "oklch(0.55 0.19 220)",
      sidebar: "oklch(0.09 0.015 264)",
      editor: "oklch(0.135 0.015 264)",
      terminal: "oklch(0.08 0.01 264)",
      statusBar: "oklch(0.17 0.04 220)",
    },
  },
] as const;

export const DEFAULT_DARK_THEME_ID: ThemeId = "t3-dark";
export const DEFAULT_LIGHT_THEME_ID: ThemeId = "t3-light";

export function getThemeById(id: ThemeId): AppTheme {
  // ThemeId is a closed union — find will always succeed for valid inputs.
  // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
  return BUILT_IN_THEMES.find((t) => t.id === id)!;
}

